mapper.select:
SELECT gc.id, gc.user_id as userId, u.username as username, gc.type, gc.prompt, gc.result_url as resultUrl, gc.cover_url as coverUrl, gc.task_id as taskId, gc.status, gc.error_msg as errorMsg, gc.model_used as modelUsed, gc.deleted as deleted, gc.create_time as createTime, gc.update_time as updateTime FROM ai_generated_content gc LEFT JOIN sys_user u ON gc.user_id = u.id WHERE u.deleted = 0
AND gc.user_id = #{userId}
AND gc.type = #{type}
AND gc.status = #{status}
ORDER BY gc.create_time DESC
